          data-testid="button-logout"
        >
          <LogOut className={`h-5 w-5 ${effectiveCollapsed ? "" : "mr-3"} flex-shrink-0`} />
          {!effectiveCollapsed && <span>{t('nav.logout')}</span>}
        </button>
      </div>
    </div>
  );
}

