        <Bar dataKey="payouts" fill="#3b82f6" name={t('financial.chartPayouts')} />
        <Bar dataKey="margin" fill="#8b5cf6" name={t('financial.chartMargin')} />
      </BarChart>
    </ResponsiveContainer>
  );
}

