                </div>
                {selectedClient.tradeName && (
                  <div>
                    <p className="text-sm font-semibold text-muted-foreground mb-1">Trade Name</p>
                    <p className="text-base text-foreground">{selectedClient.tradeName}</p>
                  </div>
                )}
